<template><div class="page-content"><PageHeader eyebrow="Delivery execution" title="Pipeline Runs" description="统一查看 Tekton PipelineRun、状态、耗时与失败记录"><el-button :loading="loading" @click="load">刷新</el-button></PageHeader><div class="metrics"><MetricCard title="当前结果" :value="total" icon="↯"/><MetricCard title="成功" :value="counts.succeeded" icon="✓" tone="green"/><MetricCard title="运行中" :value="counts.running" icon="↻" tone="blue"/><MetricCard title="失败" :value="counts.failed" icon="!" tone="red"/></div><section class="surface table-card"><div class="toolbar"><div><el-input v-model="query" placeholder="搜索 PipelineRun 或应用…" clearable/><el-select v-model="status" style="width:130px"><el-option label="全部状态" value=""/><el-option v-for="s in statuses" :key="s" :label="s" :value="s"/></el-select></div><span>{{total}} pipeline runs</span></div><el-skeleton :loading="loading" animated :rows="7"><el-table v-if="items.length" :data="items" @row-click="open"><el-table-column label="PipelineRun" min-width="260"><template #default="{row}"><div class="run-name"><span>↯</span><div><b>{{row.name}}</b><small>{{row.pipeline||'Pipeline'}}</small></div></div></template></el-table-column><el-table-column label="应用" min-width="130"><template #default="{row}">{{row.application||'—'}}</template></el-table-column><el-table-column label="分支" width="100"><template #default="{row}"><code>{{row.branch||'—'}}</code></template></el-table-column><el-table-column label="状态" width="125"><template #default="{row}"><StatusBadge :status="row.status"/></template></el-table-column><el-table-column label="耗时" width="100"><template #default="{row}">{{duration(row)}}</template></el-table-column><el-table-column label="开始时间" width="170"><template #default="{row}">{{format(row.started_at||row.created_at)}}</template></el-table-column><el-table-column label="镜像" min-width="200"><template #default="{row}"><code class="image">{{row.image||'—'}}</code></template></el-table-column><el-table-column label="操作" width="90" fixed="right"><template #default="{row}"><el-button link @click.stop="open(row)">详情</el-button></template></el-table-column></el-table><EmptyState v-else title="没有 PipelineRun" description="调整筛选条件，或从应用详情发起一次发布。"/></el-skeleton><footer><el-pagination v-model:current-page="page" :page-size="pageSize" layout="prev,pager,next" :total="total"/></footer></section></div></template>
<script setup lang="ts">import{computed,onMounted,reactive,ref,watch}from'vue';import{useRouter}from'vue-router';import{pipelineApi}from'../api/pipeline';import PageHeader from'../components/common/PageHeader.vue';import MetricCard from'../components/common/MetricCard.vue';import StatusBadge from'../components/common/StatusBadge.vue';import EmptyState from'../components/common/EmptyState.vue';type Run=Awaited<ReturnType<typeof pipelineApi.list>>['items'][number];const router=useRouter(),items=ref<Run[]>([]),total=ref(0),page=ref(1),pageSize=20,status=ref(''),query=ref(''),loading=ref(false),statuses=['Succeeded','Running','Pending','Failed'],counts=reactive({succeeded:0,running:0,failed:0});async function load(){loading.value=true;try{const data=await pipelineApi.list({page:page.value,pageSize,status:status.value||undefined,query:query.value||undefined});items.value=data.items;total.value=data.total;counts.succeeded=items.value.filter(i=>i.status==='Succeeded').length;counts.running=items.value.filter(i=>['Running','Pending'].includes(i.status)).length;counts.failed=items.value.filter(i=>i.status==='Failed').length}finally{loading.value=false}}const format=(v?:string)=>v?new Date(v).toLocaleString('zh-CN',{hour12:false}):'—',duration=(run:Run)=>run.started_at&&run.finished_at?`${Math.max(0,Math.round((new Date(run.finished_at).getTime()-new Date(run.started_at).getTime())/1000))}s`:run.status==='Running'?'Running':'—',open=(run:Run)=>router.push(`/pipelines/${run.name}`);let searchTimer:number;watch([page,status],load);watch(query,()=>{window.clearTimeout(searchTimer);searchTimer=window.setTimeout(()=>{page.value=1;load()},300)});onMounted(load)

</script>
<style scoped>.metrics{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-bottom:14px}.table-card{overflow:hidden}.toolbar{height:58px;padding:0 16px;display:flex;align-items:center;justify-content:space-between;border-bottom:1px solid var(--border-soft)}.toolbar>div{display:flex;gap:8px}.toolbar .el-input{width:240px}.toolbar>span{font-size:12px;color:var(--muted)}.run-name{display:flex;align-items:center;gap:9px}.run-name>span{width:29px;height:29px;display:grid;place-items:center;border-radius:7px;background:var(--primary-soft);color:#9185ed}.run-name b,.run-name small{display:block}.run-name b{font-size:13px}.run-name small{font-size:12px;color:var(--muted);margin-top:4px}code{font-size:12px;color:#99a3b4}.image{display:block;overflow:hidden;text-overflow:ellipsis}footer{display:flex;justify-content:flex-end;padding:12px 16px;border-top:1px solid var(--border-soft)}</style>
